export function getQuestionsForDomain(domainId: string) {
  return OPS_QUESTION_LIBRARY.filter((q) => q.domain_id === domainId);
}

export function getWorkflowById(workflowId: string) {
  return OPS_WORKFLOWS.find((w) => w.workflow_id === workflowId);
}

export function mapScoreToFindingBand(score: number) {
  if (score <= 2) return '1-2';
  if (score === 3) return '3';
  return '4-5';
}
